import React, { useState } from 'react';

function TableauAvecPagination({ data, titre }) {
  const [page, setPage] = useState(1);
  const itemsParPage = 9;

  // Calcule les éléments à afficher
  const startIndex = (page - 1) * itemsParPage;
  const currentItems = data.slice(startIndex, startIndex + itemsParPage);
  const totalPages = Math.ceil(data.length / itemsParPage);

  const nextPage = () => setPage((p) => Math.min(p + 1, totalPages));
  const prevPage = () => setPage((p) => Math.max(p - 1, 1));

  return (
    <div style={{ marginTop: '20px' }}>
      <h3>{titre} ({data.length})</h3>
      <table border="1" cellPadding="6" style={{ width: '100%' }}>
        <thead>
          <tr><th>UserID</th><th>Nom</th><th>Titre</th></tr>
        </thead>
        <tbody>
          {currentItems.map((u) => (
            <tr key={u.USERID}>
              <td>{u.USERID}</td>
              <td>{u.Nom}</td>
              <td>{u.TITLE}</td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* Pagination */}
      <div style={{ marginTop: '10px', display: 'flex', justifyContent: 'space-between' }}>
        <button onClick={prevPage} disabled={page === 1}>⬅ Précédent</button>
        <span>Page {page} / {totalPages}</span>
        <button onClick={nextPage} disabled={page === totalPages}>Suivant ➡</button>
      </div>
    </div>
  );
}

export default TableauAvecPagination;
